namespace sv_5365b31dd6a543d18df0f39cf319e2e2.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@using sv_5365b31dd6a543d18df0f39cf319e2e2.Services

<div class="card product-card h-100 @(Product.InStock ? "" : "out-of-stock")" @onclick="HandleCardClick" role="button">
    <div class="product-image-placeholder d-flex align-items-center justify-content-center bg-light" style="height: 180px;">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <div class="mb-2" title="@Product.Rating out of 5">
            @GetStarRating(Product.Rating)
        </div>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string GetStarRating(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}

@using sv_5365b31dd6a543d18df0f39cf319e2e2.Services

<div class="catalog-sidebar p-3 border rounded">
    <h5>Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-semibold">Category</label>
        @if (Categories is not null)
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                           checked="@selectedCategories.Contains(category)"
                           @onchange="@(e => ToggleCategory(category, (bool)(e.Value ?? false)))" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Price Range</label>
        <div class="d-flex gap-2 align-items-center">
            <input type="number" class="form-control form-control-sm" placeholder="Min"
                   value="@minPrice" @onchange="@(e => minPrice = ParseDecimal(e.Value))" />
            <span>–</span>
            <input type="number" class="form-control form-control-sm" placeholder="Max"
                   value="@maxPrice" @onchange="@(e => maxPrice = ParseDecimal(e.Value))" />
        </div>
    </div>

    <div class="mb-3">
        <div class="form-check">
            <input class="form-check-input" type="checkbox" id="inStockOnly"
                   checked="@inStockOnly" @onchange="@(e => inStockOnly = (bool)(e.Value ?? false))" />
            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
        </div>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter]
    public List<string>? Categories { get; set; }

    [Parameter]
    public ProductFilter? CurrentFilter { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    [Parameter]
    public EventCallback OnFilterCleared { get; set; }

    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    protected override void OnParametersSet()
    {
        if (CurrentFilter is not null)
        {
            selectedCategories = CurrentFilter.Categories is not null
                ? new HashSet<string>(CurrentFilter.Categories)
                : new HashSet<string>();
            minPrice = CurrentFilter.MinPrice;
            maxPrice = CurrentFilter.MaxPrice;
            inStockOnly = CurrentFilter.InStockOnly;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        await OnFilterCleared.InvokeAsync();
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@using sv_5365b31dd6a543d18df0f39cf319e2e2.Services

<div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
    @foreach (var product in Products)
    {
        <div class="col">
            <ProductCard Product="@product"
                         OnSelected="OnProductSelected"
                         OnAddToCart="OnAddToCart" />
        </div>
    }
</div>

