+    public EventCallback<ProductFilter> OnFilterApplied { get; set; }
+
+    [Parameter]
+    public EventCallback OnFilterCleared { get; set; }
+
+    private HashSet<string> selectedCategories = new();
+    private decimal? minPrice;
+    private decimal? maxPrice;
+    private bool inStockOnly;
+
+    protected override void OnParametersSet()
+    {
+        if (CurrentFilter is not null)
+        {
+            selectedCategories = CurrentFilter.Categories is not null
+                ? new HashSet<string>(CurrentFilter.Categories)
+                : new HashSet<string>();
+            minPrice = CurrentFilter.MinPrice;
+            maxPrice = CurrentFilter.MaxPrice;
+            inStockOnly = CurrentFilter.InStockOnly;
+        }
+    }
+
