@page "/catalog"
@using sv_5365b31dd6a543d18df0f39cf319e2e2.Components.Catalog
@using sv_5365b31dd6a543d18df0f39cf319e2e2.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="row">
    <div class="col-md-3">
        <CatalogSidebar Categories="@categories"
                        CurrentFilter="@filter"
                        OnFilterApplied="HandleFilterApplied"
                        OnFilterCleared="HandleFilterCleared" />
    </div>

    <div class="col-md-9">
        @if (isLoading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
                <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryLoad">Retry</button>
            </div>
        }
        else if (pagedResult is null || pagedResult.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products match your filters. Try adjusting your search criteria.
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@sortBy"
                            TotalCount="@pagedResult.TotalCount"
                            Page="@pagedResult.Page"
                            PageSize="@pagedResult.PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="@pagedResult.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            @if (TotalPages > 1)
            {
                <div class="mt-4">
                    <CatalogPagination CurrentPage="@currentPage"
                                       TotalPages="@TotalPages"
                                       OnPageChanged="HandlePageChanged" />
                </div>
            }
        }
    </div>
</div>

@code {
    private List<string>? categories;
    private ProductFilter filter = new(null, null, null, false);
    private PagedResult<Product>? pagedResult;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;
    private bool isLoading = true;
    private string? errorMessage;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private int TotalPages => pagedResult is null || pagedResult.PageSize == 0
        ? 1
        : (int)Math.Ceiling((double)pagedResult.TotalCount / pagedResult.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var categoriesTask = categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(categories);
            var productsTask = ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);

            await Task.WhenAll(categoriesTask, productsTask);

            categories = await categoriesTask;
            pagedResult = await productsTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter newFilter)
    {
        filter = newFilter;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleFilterCleared()
    {
        filter = new ProductFilter(null, null, null, false);
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string newSortBy)
    {
        sortBy = newSortBy;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

